class InscriptionPage extends StatefulWidget {
  @override
  _InscriptionPageState createState() => _InscriptionPageState();
}

class _InscriptionPageState extends State<InscriptionPage> {
  final TextEditingController _nomController = TextEditingController();
  final TextEditingController _emailController = TextEditingController();
  bool _accepteConditions = false;

  void _inscrire() {
    if (_accepteConditions) {
      showDialog(
        context: context,
        builder: (context) => AlertDialog(
          title: Text('Bienvenue ${_nomController.text}'),
          content: Text('Inscription réussie avec ${_emailController.text}'),
        ),
      );
    } else {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Vous devez accepter les conditions')),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Inscription')),
      body: Padding(
        padding: EdgeInsets.all(16),
        child: Column(
          children: [
            TextField(controller: _nomController, decoration: InputDecoration(labelText: 'Nom')),
            TextField(controller: _emailController, decoration: InputDecoration(labelText: 'Email')),
            Row(
              children: [
                Checkbox(
                  value: _accepteConditions,
                  onChanged: (value) => setState(() => _accepteConditions = value!),
                ),
                Text('J\'accepte les conditions générales'),
              ],
            ),
            ElevatedButton(onPressed: _inscrire, child: Text('S\'inscrire')),
          ],
        ),
      ),
    );
  }
}
