```dart
class VolumeControl extends StatefulWidget {
  @override
  _VolumeControlState createState() => _VolumeControlState();
}

class _VolumeControlState extends State<VolumeControl> {
  double _volume = 50;
  bool _sonActive = true;

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        SwitchListTile(
          title: Text('Activer le son'),
          value: _sonActive,
          onChanged: (value) {
            setState(() {
              _sonActive = value;
              if (!_sonActive) _volume = 0;
            });
          },
        ),
        Slider(
          value: _sonActive ? _volume : 0,
          min: 0,
          max: 100,
          divisions: 10,
          onChanged: _sonActive ? (value) => setState(() => _volume = value) : null,
        ),
        Text('Volume : ${_sonActive ? _volume.round() : 0} %'),
      ],
    );
  }
}
```
Le Slider est désactivé en passant `onChanged: null` lorsque `_sonActive` est faux. La valeur affichée est mise à 0.

