```dart
class ProduitForm extends StatefulWidget {
  @override
  _ProduitFormState createState() => _ProduitFormState();
}

class _ProduitFormState extends State<ProduitForm> {
  final _formKey = GlobalKey<FormState>();
  String nom = '';
  double prix = 0;
  bool disponible = true;
  String categorie = 'Électronique';
  double quantite = 50;
  bool accepteCGU = false;

  bool get isFormValid =>
      nom.trim().length >= 3 && prix > 0 && accepteCGU;

  void _submit() {
    if (_formKey.currentState!.validate() && isFormValid) {
      showDialog(
        context: context,
        builder: (context) => AlertDialog(
          title: Text('Produit enregistré'),
          content: Text('Nom: $nom\nPrix: $prix\nDispo: $disponible\nCatégorie: $categorie\nQté: $quantite'),
        ),
      );
    } else {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Corrigez les erreurs avant de soumettre')),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Nouveau produit')),
      body: Form(
        key: _formKey,
        child: ListView(
          padding: EdgeInsets.all(16),
          children: [
            TextFormField(
              decoration: InputDecoration(labelText: 'Nom *'),
              onChanged: (value) => setState(() => nom = value),
              validator: (value) => value!.trim().length < 3 ? 'Min 3 caractères' : null,
            ),
            TextFormField(
              decoration: InputDecoration(labelText: 'Prix *'),
              keyboardType: TextInputType.number,
              onChanged: (value) => setState(() => prix = double.tryParse(value) ?? 0),
              validator: (value) => double.tryParse(value ?? '') != null && double.parse(value!) > 0 ? null : 'Prix positif requis',
            ),
            SwitchListTile(
              title: Text('Disponible'),
              value: disponible,
              onChanged: (value) => setState(() => disponible = value),
            ),
            Text('Catégorie'),
            Row(
              children: [
                Radio(
                  value: 'Électronique',
                  groupValue: categorie,
                  onChanged: (value) => setState(() => categorie = value!),
                ),
                Text('Électronique'),
                Radio(
                  value: 'Vêtement',
                  groupValue: categorie,
                  onChanged: (value) => setState(() => categorie = value!),
                ),
                Text('Vêtement'),
                Radio(
                  value: 'Maison',
                  groupValue: categorie,
                  onChanged: (value) => setState(() => categorie = value!),
                ),
                Text('Maison'),
              ],
            ),
            Text('Quantité : ${quantite.round()}'),
            Slider(
              value: quantite,
              min: 0,
              max: 100,
              divisions: 100,
              onChanged: (value) => setState(() => quantite = value),
            ),
            CheckboxListTile(
              title: Text('J\'accepte les CGU *'),
              value: accepteCGU,
              onChanged: (value) => setState(() => accepteCGU = value!),
            ),
            ElevatedButton(
              onPressed: isFormValid ? _submit : null,
              child: Text('Enregistrer'),
            ),
            Divider(),
            Text('Résumé :', style: TextStyle(fontWeight: FontWeight.bold)),
            Text('Nom: $nom'),
            Text('Prix: $prix'),
            Text('Dispo: $disponible'),
            Text('Catégorie: $categorie'),
            Text('Quantité: ${quantite.round()}'),
          ],
        ),
      ),
    );
  }
}
